(()=>{const DATA='/assets/data/customer.os.v2.20260505.json';const h=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));const copy=async t=>{try{await navigator.clipboard.writeText(String(t||''));return true}catch(e){const a=document.createElement('textarea');a.value=String(t||'');a.style.position='fixed';a.style.opacity='0';document.body.appendChild(a);a.select();document.execCommand('copy');a.remove();return true}};const toast=m=>{let el=document.querySelector('.toast-os');if(!el){el=document.createElement('div');el.className='toast-os';document.body.appendChild(el)}el.textContent=m;el.classList.add('is-show');clearTimeout(el._t);el._t=setTimeout(()=>el.classList.remove('is-show'),1500)};const ctx=()=>{const p=location.pathname.toLowerCase();if(p.includes('sk-holdings'))return{type:'provider',slug:'skholdings',label:'SK 홀딩스 IRON888 가입 안내'};if(p.includes('queenbee'))return{type:'provider',slug:'queenbee',label:'여왕벌 SEOA 가입 안내'};if(p.includes('anybet'))return{type:'provider',slug:'anybet',label:'ANY BET SEOA 가입 안내'};if(p.includes('udt'))return{type:'provider',slug:'udt',label:'UDT SEOA 가입 안내'};if(p.includes('payout-risk')||p.includes('withdraw'))return{type:'flow',flow:'payout',label:'출금 전 자료 확인'};if(p.includes('sports-toto'))return{type:'flow',flow:'sports',label:'조건 확인 상담 안내'};if(p.includes('casino')||p.includes('slot')||p.includes('minigame')||p.includes('event')||p.includes('bonus'))return{type:'flow',flow:'event',label:'이벤트 조건 확인'};return null};const addBlogCta=()=>{const article=document.querySelector('.pro-article__body');if(!article||document.querySelector('.customer-os-cta'))return;const c=ctx();if(!c)return;const btn=c.type==='provider'?`<button class="pro-btn pro-btn--primary" data-auto-consult-provider="${h(c.slug)}">${h(c.label)}</button>`:`<button class="pro-btn pro-btn--primary" data-auto-consult-open="${h(c.flow)}">${h(c.label)}</button>`;const box=document.createElement('section');box.className='customer-os-card customer-os-cta';box.innerHTML=`<span class="pro-kicker">맞춤 상담</span><h2>이 글과 관련된 안내를 바로 확인하세요</h2><p>현재 페이지 주제에 맞춰 가입코드, 이벤트 조건, 출금 확인, 상담센터 안내를 자동으로 정리합니다.</p><div class="customer-os-actions">${btn}<button class="pro-btn" data-auto-consult-open="provider">보증업체 선택</button><a class="pro-btn" href="/consult/">상담센터 보기</a></div>`;article.appendChild(box)};const addTerms=async()=>{if(!document.querySelector('.pro-article__body'))return;try{const d=await fetch(DATA,{cache:'no-store'}).then(r=>r.json());const article=document.querySelector('.pro-article__body');if(!article||document.querySelector('.customer-os-term-box'))return;const box=document.createElement('section');box.className='customer-os-card customer-os-term-box';box.innerHTML=`<span class="pro-kicker">용어 빠른 설명</span><h2>글에서 자주 나오는 용어</h2><div class="customer-os-term-grid">${(d.terms||[]).map(t=>`<button type="button" class="customer-os-term" data-term-desc="${h(t.desc)}">${h(t.term)}</button>`).join('')}</div><p class="customer-os-note" data-term-output>용어를 누르면 짧은 설명이 표시됩니다.</p>`;article.appendChild(box)}catch(e){}};const renderToday=async()=>{const target=document.querySelector('[data-today-check]');if(!target)return;try{const d=await fetch(DATA,{cache:'no-store'}).then(r=>r.json());const t=d.today;target.innerHTML=`<div class="customer-os-grid">${t.providers.map(p=>`<a class="customer-os-mini" href="${h(p.link)}"><strong>${h(p.name)}</strong><span>가입코드 ${h(p.code)}</span><span>${h(p.status)}</span></a>`).join('')}</div><ul class="auto-consult-checks">${t.checks.map(x=>`<li>${h(x)}</li>`).join('')}</ul>`}catch(e){}};const bind=()=>{document.addEventListener('click',async e=>{const term=e.target.closest('.customer-os-term');if(term){const out=document.querySelector('[data-term-output]');if(out)out.textContent=term.dataset.termDesc||''}const prov=e.target.closest('[data-auto-consult-provider]');if(prov){e.preventDefault();document.querySelector('.auto-consult-launcher')?.click();setTimeout(()=>{const panel=document.querySelector('.auto-consult-panel');panel?.classList.add('is-open');panel?.dispatchEvent(new CustomEvent('autoConsultProvider',{detail:{slug:prov.dataset.autoConsultProvider}}))},60)}const cp=e.target.closest('[data-copy-text]');if(cp){e.preventDefault();await copy(cp.dataset.copyText);toast('문구를 복사했습니다')}})};document.addEventListener('DOMContentLoaded',()=>{addBlogCta();addTerms();renderToday();bind()})})();